"use client";

import React from "react";
import * as Scrollytelling from "@bsmnt/scrollytelling";

type Intensity = "subtle" | "aggressive";

export interface CardStackDealProps {
  /** the cards to deal, in order — each must stand alone if motion never runs */
  cards: React.ReactNode[];
  intensity?: Intensity;
  className?: string;
}

const prefers = (q: string): boolean =>
  typeof window !== "undefined" &&
  typeof window.matchMedia === "function" &&
  window.matchMedia(q).matches;

/*
 * A dealt-hand card reveal on @bsmnt/scrollytelling (declarative GSAP ScrollTrigger) — the same rail as
 * kinetic-text-split / parallax-depth / pinned-crossfade. Cards rise and rotate into a fanned hand,
 * staggered in array order, scrubbed to scroll.
 *
 * SAFETY IS BAKED IN, not left to the caller:
 *  - prefers-reduced-motion OR a coarse pointer renders a plain vertical list: no fan, no overlap, no
 *    motion. This is not a lesser fallback -- a fanned row of overlapping cards on a 375px screen is
 *    genuinely unreadable, so touch gets the readable layout by design, not as a concession.
 *  - fewer than 2 cards has no hand to deal, so it degrades to the same plain list.
 *  - the fan angle and travel derive from `intensity` and the card COUNT; there is no per-card timing
 *    knob for the agent to get wrong. A bad prop degrades, it cannot desynchronise the deal.
 *  - only transform + opacity animate (never layout), and every card is fully readable at rest.
 *
 * The resting fan angle is plain CSS on an outer wrapper; GSAP only ever owns the deal-in delta on an
 * inner node. Keeping the two on separate elements means the library and the stylesheet never fight
 * over one transform property.
 */
export function CardStackDeal({ cards, intensity = "aggressive", className }: CardStackDealProps) {
  const list = (Array.isArray(cards) ? cards : []).filter((c) => c !== null && c !== undefined && c !== false);

  const staticFallback = prefers("(prefers-reduced-motion: reduce)") || prefers("(pointer: coarse)");

  if (staticFallback || list.length < 2) {
    return (
      <section className={className}>
        {list.map((card, i) => (
          <div key={i}>{card}</div>
        ))}
      </section>
    );
  }

  const n = list.length;
  // Total scroll % the deal occupies; each card gets an overlapping slice of it, in array order.
  const span = intensity === "aggressive" ? 60 : 45;
  const step = span / n;
  const fanDeg = intensity === "aggressive" ? 5 : 2.5;
  const from =
    intensity === "aggressive"
      ? { opacity: 0, yPercent: 55, rotate: -10 }
      : { opacity: 0, yPercent: 25, rotate: -4 };
  const center = (n - 1) / 2;

  return (
    <section className={className}>
      <Scrollytelling.Root start="top 75%" end="bottom 60%">
        <div style={{ display: "flex", justifyContent: "center", alignItems: "flex-end", flexWrap: "nowrap" }}>
          {list.map((card, i) => {
            const start = Math.min(98, Math.round(i * step));
            const raw = Math.round(i * step + step * 1.8);
            const end = Math.min(100, raw > start ? raw : start + 1);
            return (
              <div
                key={i}
                style={{
                  transform: "rotate(" + ((i - center) * fanDeg).toFixed(2) + "deg)",
                  transformOrigin: "bottom center",
                  marginLeft: i === 0 ? 0 : "-2%",
                  zIndex: i,
                  flex: "0 1 auto"
                }}
              >
                <Scrollytelling.Animation tween={{ start, end, from }}>
                  <div>{card}</div>
                </Scrollytelling.Animation>
              </div>
            );
          })}
        </div>
      </Scrollytelling.Root>
    </section>
  );
}

export default CardStackDeal;

usage_example:
import { CardStackDeal } from './component'

// An ORDERED array of cards, dealt in like a hand as the section scrolls into view.
// Pass 3-6 real, on-brief cards -- each must stand alone if motion never runs. The deal timing and
// fan angle are computed inside from the card count; there is no per-card timing to set.
export default function Section() {
  return (
    <section className="py-24 px-6 bg-background">
      <CardStackDeal
        intensity="aggressive"
        cards={[
          <article key="1" className="w-[190px] h-[250px] rounded-xl bg-card border border-border p-4">
            <h3 className="text-card-foreground font-semibold">First step</h3>
            <p className="mt-2 text-sm text-muted-foreground">What happens first, in the brand voice.</p>
          </article>,
          <article key="2" className="w-[190px] h-[250px] rounded-xl bg-card border border-border p-4">
            <h3 className="text-card-foreground font-semibold">Second step</h3>
            <p className="mt-2 text-sm text-muted-foreground">The next beat it resolves into.</p>
          </article>,
          <article key="3" className="w-[190px] h-[250px] rounded-xl bg-card border border-border p-4">
            <h3 className="text-card-foreground font-semibold">Third step</h3>
            <p className="mt-2 text-sm text-muted-foreground">Where it lands.</p>
          </article>
        ]}
      />
    </section>
  )
}
